/**
 * HumanBody3D — composant Three.js isolé
 *
 * Props :
 *   width         string  CSS width  (défaut "100%")
 *   height        string  CSS height (défaut "600px")
 *   background    string  CSS background (défaut "transparent")
 *   wireColor     number  hex couleur wireframe  (défaut 0x60a5fa)
 *   fillOpacity   number  opacité du volume intérieur (défaut 0.18)
 *   showPoints    bool    afficher les points d'acupuncture (défaut true)
 *   showMeridians bool    afficher les méridiens (défaut true)
 *   autoRotate    bool    rotation automatique (défaut true)
 *   onPointClick  func    callback(point) quand on clique un acupoint
 */
export default function HumanBody3D({
  width = "100%",
  height = "600px",
  background = "transparent",
  wireColor = 0x1e40af,
  fillOpacity = 0.08,
  showPoints = true,
  showMeridians = true,
  autoRotate = true,
  onPointClick,
}) {
  const containerRef = useRef(null);
  const stateRef = useRef({ rotating: autoRotate });

  useEffect(() => {
    stateRef.current.rotating = autoRotate;
  }, [autoRotate]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const getSize = () => ({ w: container.clientWidth || 400, h: container.clientHeight || 600 });
    const { w: initW, h: initH } = getSize();

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(32, initW / initH, 0.1, 100);
    camera.position.set(0, 0.2, 11);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setClearColor(0x000000, 0);
    renderer.setSize(initW, initH);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    container.appendChild(renderer.domElement);

    const canvas = renderer.domElement;
    canvas.style.display = "block";
    canvas.style.width = "100%";
    canvas.style.height = "100%";
    canvas.style.touchAction = "none";
    canvas.style.cursor = "grab";

    // Lumières
    scene.add(new THREE.AmbientLight(0xffffff, 0.85));
    const p1 = new THREE.PointLight(0x2563eb, 1.2, 30);
    p1.position.set(4, 3, 6);
    scene.add(p1);
    const p2 = new THREE.PointLight(0x6366f1, 0.7, 30);
    p2.position.set(-4, -2, 5);
    scene.add(p2);

    // Groupe corps
    const body = new THREE.Group();
    scene.add(body);

    const positions = new Float32Array(BODY_VERTS);
    const bodyGeo = new THREE.BufferGeometry();
    bodyGeo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    bodyGeo.setIndex(new THREE.BufferAttribute(new Uint16Array(BODY_FACES), 1));
    bodyGeo.computeVertexNormals();

    // Volume intérieur
    body.add(new THREE.Mesh(bodyGeo, new THREE.MeshPhongMaterial({
      color: 0x1e3a8a, transparent: true, opacity: fillOpacity,
      shininess: 90, flatShading: true, side: THREE.DoubleSide, depthWrite: false,
    })));

    // Wireframe triangulé (toutes les arêtes → beau maillage basse-poly)
    body.add(new THREE.LineSegments(
      new THREE.WireframeGeometry(bodyGeo),
      new THREE.LineBasicMaterial({ color: wireColor, transparent: true, opacity: 0.55 })
    ));

    // Acupoints
    const pointMeshes = [];
    const halos = [];

    if (showPoints) {
      const pointGroup = new THREE.Group();
      ACUPOINTS.forEach((p) => {
        const halo = new THREE.Mesh(
          new THREE.SphereGeometry(0.08, 14, 14),
          new THREE.MeshBasicMaterial({ color: p.color, transparent: true, opacity: 0.32 })
        );
        halo.position.set(...p.pos);
        pointGroup.add(halo);
        halos.push(halo);

        const core = new THREE.Mesh(
          new THREE.SphereGeometry(0.035, 14, 14),
          new THREE.MeshBasicMaterial({ color: p.color })
        );
        core.position.set(...p.pos);
        core.userData = { point: p };
        pointGroup.add(core);
        pointMeshes.push(core);
      });
      body.add(pointGroup);
    }

    // Méridiens
    const meridians = [];
    if (showMeridians) {
      MERIDIAN_ROUTES.forEach((route) => {
        const curve = new THREE.CatmullRomCurve3(route.points.map((p) => new THREE.Vector3(...p)));
        body.add(new THREE.Line(
          new THREE.BufferGeometry().setFromPoints(curve.getPoints(80)),
          new THREE.LineBasicMaterial({ color: 0xf59e0b, transparent: true, opacity: 0.55 })
        ));
        const particle = new THREE.Mesh(
          new THREE.SphereGeometry(0.05, 10, 10),
          new THREE.MeshBasicMaterial({ color: route.color })
        );
        body.add(particle);
        meridians.push({ curve, particle, t: Math.random() });
      });
    }

    // Interaction
    const raycaster = new THREE.Raycaster();
    const mouse = new THREE.Vector2();
    let isDown = false, dragged = false, lastX = 0, lastY = 0;
    let yaw = 0, pitch = 0, velX = 0;

    const getXY = (e) => {
      const r = canvas.getBoundingClientRect();
      const t = e.touches?.[0] || e.changedTouches?.[0] || e;
      return { x: t.clientX - r.left, y: t.clientY - r.top };
    };

    const onDown = (e) => {
      const { x, y } = getXY(e);
      isDown = true; dragged = false; lastX = x; lastY = y;
      canvas.style.cursor = "grabbing";
    };
    const onMove = (e) => {
      if (!isDown) return;
      const { x, y } = getXY(e);
      const dx = x - lastX, dy = y - lastY;
      if (Math.abs(dx) > 3 || Math.abs(dy) > 3) dragged = true;
      yaw += dx * 0.008; pitch += dy * 0.005;
      pitch = Math.max(-0.7, Math.min(0.7, pitch));
      velX = dx * 0.008;
      lastX = x; lastY = y;
    };
    const onUp = (e) => {
      canvas.style.cursor = "grab";
      if (isDown && !dragged && onPointClick) {
        const { x, y } = getXY(e);
        const r = canvas.getBoundingClientRect();
        mouse.x = (x / r.width) * 2 - 1;
        mouse.y = -(y / r.height) * 2 + 1;
        raycaster.setFromCamera(mouse, camera);
        const hits = raycaster.intersectObjects(pointMeshes, false);
        if (hits.length > 0) onPointClick(hits[0].object.userData.point);
      }
      isDown = false;
    };

    canvas.addEventListener("mousedown", onDown);
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    canvas.addEventListener("touchstart", onDown, { passive: true });
    window.addEventListener("touchmove", onMove, { passive: true });
    window.addEventListener("touchend", onUp);

    const resize = () => {
      const { w, h } = getSize();
      if (!w || !h) return;
      camera.aspect = w / h;
      camera.updateProjectionMatrix();
      renderer.setSize(w, h);
    };
    const ro = new ResizeObserver(resize);
    ro.observe(container);
    window.addEventListener("resize", resize);
    setTimeout(resize, 50);

    let animId, time = 0;
    const animate = () => {
      animId = requestAnimationFrame(animate);
      time += 0.016;

      if (stateRef.current.rotating && !isDown) {
        yaw += 0.003; velX *= 0.95;
      } else {
        velX *= 0.92; yaw += velX * 0.5;
      }
      body.rotation.y = yaw;
      body.rotation.x = pitch;

      halos.forEach((h, i) => {
        const s = 1 + Math.sin(time * 2.2 + i) * 0.4;
        h.scale.set(s, s, s);
        h.material.opacity = 0.2 + Math.sin(time * 2 + i) * 0.12;
      });

      meridians.forEach((m, i) => {
        m.t += 0.004 + (i % 3) * 0.001;
        if (m.t > 1) m.t = 0;
        m.particle.position.copy(m.curve.getPoint(m.t));
        const s = 1 + Math.sin(time * 4 + i) * 0.4;
        m.particle.scale.set(s, s, s);
      });

      renderer.render(scene, camera);
    };
    animate();

    return () => {
      cancelAnimationFrame(animId);
      ro.disconnect();
      window.removeEventListener("resize", resize);
      canvas.removeEventListener("mousedown", onDown);
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
      canvas.removeEventListener("touchstart", onDown);
      window.removeEventListener("touchmove", onMove);
      window.removeEventListener("touchend", onUp);
      renderer.dispose();
      if (container.contains(canvas)) container.removeChild(canvas);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div
      ref={containerRef}
      style={{ width, height, background, display: "block", overflow: "hidden" }}
    />
  );
}